package com.salarzudfekr.persianaichat;
import android.app.*;import android.os.*;import android.content.*;import android.graphics.*;import android.net.Uri;import android.view.*;import android.view.inputmethod.InputMethodManager;import android.widget.*;import org.json.*;import java.io.*;import java.net.*;import java.nio.charset.StandardCharsets;import java.util.concurrent.*;
public class MainActivity extends Activity{static final String VERSION="1.1.0",REL="https://github.com/salarzudfekr/persian-ai-chat/releases/latest";static final int BLUE=Color.rgb(37,99,235),BG=Color.rgb(245,247,251),TEXT=Color.rgb(17,24,39),MUTED=Color.rgb(107,114,128);LinearLayout msgs;ScrollView scroll;EditText input;Button send;SharedPreferences p;ExecutorService ex=Executors.newSingleThreadExecutor();Handler ui=new Handler(Looper.getMainLooper());public void onCreate(Bundle b){super.onCreate(b);p=getSharedPreferences("s",0);getWindow().getDecorView().setLayoutDirection(View.LAYOUT_DIRECTION_RTL);setContentView(screen());bot("سلام! از تنظیمات، API Key و Base URL و Model را وارد کن، بعد پیام بفرست.");}
View screen(){LinearLayout root=new LinearLayout(this);root.setOrientation(LinearLayout.VERTICAL);root.setBackgroundColor(BG);LinearLayout head=new LinearLayout(this);head.setGravity(Gravity.CENTER_VERTICAL);head.setPadding(dp(14),dp(10),dp(14),dp(8));head.setBackgroundColor(Color.WHITE);LinearLayout titles=new LinearLayout(this);titles.setOrientation(LinearLayout.VERTICAL);titles.addView(txt("چت فارسی AI",21,TEXT,true));titles.addView(txt("نسخه "+VERSION+" • OpenAI-compatible",12,MUTED,false));head.addView(titles,new LinearLayout.LayoutParams(0,-2,1));Button up=btn("آپدیت");up.setOnClickListener(v->updates());Button set=btn("تنظیمات");set.setOnClickListener(v->settings());head.addView(up);head.addView(set);root.addView(head);scroll=new ScrollView(this);msgs=new LinearLayout(this);msgs.setOrientation(LinearLayout.VERTICAL);msgs.setPadding(dp(12),dp(12),dp(12),dp(12));scroll.addView(msgs);root.addView(scroll,new LinearLayout.LayoutParams(-1,0,1));LinearLayout comp=new LinearLayout(this);comp.setGravity(Gravity.BOTTOM);comp.setPadding(dp(12),dp(8),dp(12),dp(12));comp.setBackgroundColor(Color.WHITE);input=new EditText(this);input.setHint("پیام بنویس...");input.setMinLines(1);input.setMaxLines(4);input.setGravity(Gravity.RIGHT);input.setTextDirection(View.TEXT_DIRECTION_RTL);input.setBackgroundColor(Color.rgb(243,244,246));input.setPadding(dp(12),dp(8),dp(12),dp(8));comp.addView(input,new LinearLayout.LayoutParams(0,-2,1));send=btn("ارسال");send.setTextColor(Color.WHITE);send.setBackgroundColor(BLUE);send.setOnClickListener(v->send());comp.addView(send);root.addView(comp);return root;}
TextView txt(String s,int z,int c,boolean bold){TextView t=new TextView(this);t.setText(s);t.setTextSize(z);t.setTextColor(c);t.setGravity(Gravity.RIGHT);if(bold)t.setTypeface(Typeface.DEFAULT,Typeface.BOLD);return t;}Button btn(String s){Button b=new Button(this);b.setText(s);b.setAllCaps(false);b.setTextSize(13);return b;}EditText field(String h,String v){EditText e=new EditText(this);e.setHint(h);e.setText(v);e.setSingleLine(true);e.setTextDirection(View.TEXT_DIRECTION_LTR);e.setGravity(Gravity.LEFT);return e;}
void settings(){LinearLayout box=new LinearLayout(this);box.setOrientation(LinearLayout.VERTICAL);box.setPadding(dp(8),0,dp(8),0);EditText k=field("API Key",p.getString("key","")),u=field("Base URL مثل https://example.com/v1",p.getString("url","")),m=field("Model مثل gpt-5.5",p.getString("model","gpt-5.5"));box.addView(k);box.addView(u);box.addView(m);new AlertDialog.Builder(this).setTitle("تنظیمات اتصال").setView(box).setPositiveButton("ذخیره",(d,w)->{p.edit().putString("key",k.getText().toString().trim()).putString("url",u.getText().toString().trim()).putString("model",m.getText().toString().trim()).apply();bot("تنظیمات ذخیره شد.");}).setNegativeButton("لغو",null).show();}
void updates(){new AlertDialog.Builder(this).setTitle("آپدیت برنامه").setMessage("نسخه فعلی: "+VERSION+"\nبرای دانلود نسخه جدید، صفحه Releases باز می‌شود.").setPositiveButton("باز کردن",(d,w)->startActivity(new Intent(Intent.ACTION_VIEW,Uri.parse(REL)))).setNegativeButton("بعداً",null).show();}
void send(){String msg=input.getText().toString().trim();if(msg.isEmpty())return;String k=p.getString("key",""),u=p.getString("url",""),m=p.getString("model","gpt-5.5");if(k.isEmpty()||u.isEmpty()){bot("اول تنظیمات اتصال را کامل کن.");return;}input.setText("");hide();user(msg);send.setEnabled(false);TextView wait=bot("در حال نوشتن...");ex.execute(()->{String ans=api(k,u,m,msg);ui.post(()->{wait.setText(ans);send.setEnabled(true);bottom();});});}
void user(String s){bubble(s,true);}TextView bot(String s){return bubble(s,false);}TextView bubble(String s,boolean me){LinearLayout row=new LinearLayout(this);row.setGravity(me?Gravity.LEFT:Gravity.RIGHT);row.setPadding(0,dp(5),0,dp(5));TextView b=new TextView(this);b.setText(s);b.setTextSize(15);b.setTextColor(me?Color.WHITE:TEXT);b.setGravity(Gravity.RIGHT);b.setTextDirection(View.TEXT_DIRECTION_RTL);b.setPadding(dp(12),dp(9),dp(12),dp(9));b.setBackgroundColor(me?BLUE:Color.WHITE);row.addView(b,new LinearLayout.LayoutParams((int)(getResources().getDisplayMetrics().widthPixels*.78),-2));msgs.addView(row);bottom();return b;}
String api(String key,String base,String model,String msg){HttpURLConnection c=null;try{if(base.endsWith("/"))base=base.substring(0,base.length()-1);c=(HttpURLConnection)new URL(base+"/chat/completions").openConnection();c.setRequestMethod("POST");c.setDoOutput(true);c.setConnectTimeout(30000);c.setReadTimeout(60000);c.setRequestProperty("Authorization","Bearer "+key);c.setRequestProperty("Content-Type","application/json; charset=utf-8");JSONObject body=new JSONObject();body.put("model",model);body.put("messages",new JSONArray().put(new JSONObject().put("role","user").put("content",msg)));try(OutputStream os=c.getOutputStream()){os.write(body.toString().getBytes(StandardCharsets.UTF_8));}int code=c.getResponseCode();String res=read(code>=200&&code<300?c.getInputStream():c.getErrorStream());if(code<200||code>=300)return "خطای API "+code+"\n"+res;return new JSONObject(res).getJSONArray("choices").getJSONObject(0).getJSONObject("message").getString("content");}catch(Exception e){return "خطا: "+e.getMessage();}finally{if(c!=null)c.disconnect();}}
String read(InputStream s)throws Exception{if(s==null)return"";BufferedReader r=new BufferedReader(new InputStreamReader(s,StandardCharsets.UTF_8));StringBuilder b=new StringBuilder();String l;while((l=r.readLine())!=null)b.append(l).append('\n');return b.toString();}void bottom(){ui.postDelayed(()->scroll.fullScroll(View.FOCUS_DOWN),100);}void hide(){((InputMethodManager)getSystemService(INPUT_METHOD_SERVICE)).hideSoftInputFromWindow(input.getWindowToken(),0);}int dp(int v){return(int)(v*getResources().getDisplayMetrics().density);} }
